#define _CRT_SECURE_NO_WARNINGS 1#include<stdio.h>void Print_table(int n){	int i = 0;	for (i = 0; i <= n; i++)	{		int j = 0;		for (j = 1; j <= i; j++)		{			printf("%d * %d = %d", i, j, i * j);		}		printf("\n");	}}int main(){	int n = 0;	scanf("%d", &n);	Print_table(n);	return 0;}